import requests
from requests.auth import HTTPBasicAuth

# Configuration
rabbitmq_host = 'http://localhost:15672'
username = 'guest'
password = 'guest'

vhosts = {
    'app1': ['user1', 'password1'],
    'app2': ['user2', 'password2']
}

permissions = {
    'configure': '.*',
    'write': '.*',
    'read': '.*'
}

def create_vhost(vhost_name):
    url = f"{rabbitmq_host}/api/vhosts/{vhost_name}"
    response = requests.put(url, auth=HTTPBasicAuth(username, password))
    return response.status_code == 204

def create_user(username, user_password):
    url = f"{rabbitmq_host}/api/users/{username}"
    data = {
        'password': user_password,
        'tags': 'management'
    }
    response = requests.put(url, json=data, auth=HTTPBasicAuth(username, password))
    return response.status_code == 204

def set_permissions(vhost_name, username):
    url = f"{rabbitmq_host}/api/permissions/{vhost_name}/{username}"
    response = requests.put(url, json=permissions, auth=HTTPBasicAuth(username, password))
    return response.status_code == 204

for vhost_name, user_info in vhosts.items():
    user, user_password = user_info
    if create_vhost(vhost_name):
        print(f"VHost {vhost_name} created successfully.")
    if create_user(user, user_password):
        print(f"User {user} created successfully.")
    if set_permissions(vhost_name, user):
        print(f"Permissions set for user {user} on vhost {vhost_name}.")